React + Zustand Example
import { create } from "zustand";
import { persist } from "zustand/middleware";

export const useUserStore = create(
  persist(
    (set) => ({
      user: null,
      setUser: (data) => set({ user: data }),
      clearUser: () => set({ user: null }),
    }),
    { name: "user-store", version: 1 }
  )
);

