import React from 'react';
import * as bin from './bin';

export const shell = async (
  command: string,
  setHistory: (value: string) => void,
  clearHistory: () => void,
  setCommand: React.Dispatch<React.SetStateAction<string>>,
) => {
  const args = command.split(' ');
  args[0] = args[0].toLowerCase();

  if (args[0] === 'clear') {
    clearHistory();
  } else if (command === '') {
    setHistory('');
  } else if (Object.keys(bin).indexOf(args[0]) === -1) {
    setHistory(
      `shell: command not found: ${args[0]}. Try 'help' to get started.`,
    );
  } else {
    const output = await bin[args[0]](args.slice(1));
    setHistory(output);
  }

  setCommand('');
};

import { DOM } from './utils/dom';
import DateUtils from './utils/date';
import ThemeManager from './utils/theme';
import Sidebar from './components/Sidebar';
import ChartComponent from './components/Chart';
import '../styles/index.scss';

class AdminatorApp {
  constructor() {
    this.components = new Map();
    this.isInitialized = false;
    this.themeManager = ThemeManager;

    // Initialize when DOM is ready
    DOM.ready(() => {
      this.init();
    });
  }

  init() {
    if (this.isInitialized) return;

    try {
      // Initialize core components
      this.initSidebar();
      this.initCharts();
      this.initDataTables();
      this.initDatePickers();
      this.initTheme();
      this.initMobileEnhancements();

      this.setupGlobalEvents();

      this.isInitialized = true;

      window.dispatchEvent(new CustomEvent('adminator:ready', {
        detail: { app: this },
      }));

    } catch {
      // Error initializing Adminator App
    }
  }

  initSidebar() {
    if (DOM.exists('.sidebar')) {
      const sidebar = new Sidebar();
      this.components.set('sidebar', sidebar);
    }
  }

  initCharts() {
    const hasCharts = DOM.exists('.sparkline') || DOM.exists('#line-chart'); // simplified check
    if (hasCharts) {
      const charts = new ChartComponent();
      this.components.set('charts', charts);
    }
  }

  // ... additional methods for DataTables and DatePickers ...
}
